+// Fold (icmp X, Upper) & (icmp eq (X & Mask), Val)
+// to (icmp eq (X & Mask), Val) when the mask comparison implies the range.
+// For example: (icmp ult X, 5) & (icmp eq (X & -2), 2) -> (icmp eq (X & -2), 2)
+// because if (X & -2) == 2, then X is either 2 or 3, both < 5.
+// Also handles signed comparisons: (icmp sgt X, 127) & (icmp eq (X & -32), 128)
+// because if (X & -32) == 128, then X is in [128, 159], all > 127.
+static Value *foldAndOfRangeAndMaskedEq(ICmpInst *RangeCmp, ICmpInst *MaskedCmp,
+                                        InstCombiner::BuilderTy &Builder) {
+  ICmpInst::Predicate Pred = RangeCmp->getPredicate();
+  Value *RangeVar = RangeCmp->getOperand(0);
+  const APInt *RangeC;
+  if (!match(RangeCmp->getOperand(1), m_APIntAllowPoison(RangeC)))
+    return nullptr;
+
+  // MaskedCmp should be (and X, Mask) == Val.
+  if (MaskedCmp->getPredicate() != ICmpInst::ICMP_EQ)
+    return nullptr;
+
+  Value *MaskVar;
+  const APInt *Mask, *Val;
+  if (!match(MaskedCmp->getOperand(0), m_And(m_Value(MaskVar), m_APIntAllowPoison(Mask))))
+    return nullptr;
+  if (!match(MaskedCmp->getOperand(1), m_APIntAllowPoison(Val)))
+    return nullptr;
+
+  // Both comparisons should be on the same variable.
+  if (RangeVar != MaskVar)
+    return nullptr;
+
+  // Val must be compatible with the mask (bits set in Val must be within Mask).
+  // If (Val & ~Mask) != 0, the comparison is always false.
+  if ((*Val & ~*Mask) != 0)
+    return nullptr;
+
+  // Calculate the min and max values that satisfy (X & Mask) == Val.
+  // Min is Val (all bits not in Mask are 0).
+  // Max is Val | ~Mask (all bits not in Mask are 1).
+  APInt MinVal = *Val;
+  APInt MaxVal = *Val | ~*Mask;
+
+  // Check if the range [MinVal, MaxVal] is within the comparison range.
+  bool IsInRange = false;
+  switch (Pred) {
+  default:
+    return nullptr;
+  case ICmpInst::ICMP_ULT:
+    // X < C: max value must be < C
+    IsInRange = MaxVal.ult(*RangeC);
+    break;
+  case ICmpInst::ICMP_ULE:
+    // X <= C: max value must be <= C
+    IsInRange = MaxVal.ule(*RangeC);
+    break;
+  case ICmpInst::ICMP_SLT:
+    // X <s C: max value must be <s C
+    IsInRange = MaxVal.slt(*RangeC);
+    break;
+  case ICmpInst::ICMP_SLE:
+    // X <=s C: max value must be <=s C
+    IsInRange = MaxVal.sle(*RangeC);
+    break;
+  case ICmpInst::ICMP_UGT:
+    // X > C: min value must be > C
+    IsInRange = MinVal.ugt(*RangeC);
+    break;
+  case ICmpInst::ICMP_UGE:
+    // X >= C: min value must be >= C
+    IsInRange = MinVal.uge(*RangeC);
+    break;
+  case ICmpInst::ICMP_SGT:
+    // X >s C: min value must be >s C
+    IsInRange = MinVal.sgt(*RangeC);
+    break;
+  case ICmpInst::ICMP_SGE:
+    // X >=s C: min value must be >=s C
+    IsInRange = MinVal.sge(*RangeC);
+    break;
+  }
